            <div className="flex items-center space-x-3 md:space-x-6">

              <div className="hidden md:flex items-center space-x-2 text-xs bg-green-50 text-luGreen-dark py-1.5 px-3 rounded-full border border-green-100 shadow-sm">
                <span className="relative flex h-2 w-2">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-2 w-2 bg-luGreen"></span>
                </span>
                <span className="font-medium">System Online</span>
              </div>

              <button className="p-2 text-gray-400 hover:text-luGold-dark hover:bg-yellow-50 rounded-full transition-all relative group">
                <Bell size={20} />
                <span className="absolute top-2 right-2 w-2 h-2 bg-red-500 rounded-full border-2 border-white"></span>
              </button>

              <div className="h-8 w-[1px] bg-gray-200 hidden md:block"></div>

              <button 
                onClick={onLogout}
                className="flex items-center space-x-2 bg-white hover:bg-gray-50 text-gray-600 hover:text-red-600 border border-gray-200 hover:border-red-100 transition-all py-2 px-4 rounded-xl text-sm font-medium shadow-sm hover:shadow-md active:scale-95"
              >
                <LogOut size={16} />
                <span className="hidden md:inline">Sign Out</span>
              </button>
            </div>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-grow container mx-auto px-4 lg:px-8 py-8 lg:py-12">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* Left Column: Navigation Only (3 cols) */}
          <div className="lg:col-span-3 space-y-6">

            {/* Navigation Menu */}
            <div className="bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden p-3 space-y-1 sticky top-24">
                <button 
                  onClick={() => setActiveTab('home')}
                  className={`w-full flex items-center gap-4 px-4 py-3 rounded-xl transition-all duration-200 text-sm font-bold ${activeTab === 'home' ? 'bg-green-50 text-luGreen' : 'text-gray-600 hover:bg-gray-50'}`}
                >
                    <LayoutDashboard size={20} />
                    Dashboard
                </button>
                <button 
                  onClick={() => setActiveTab('profile')}
                  className={`w-full flex items-center gap-4 px-4 py-3 rounded-xl transition-all duration-200 text-sm font-bold ${activeTab === 'profile' ? 'bg-blue-50 text-blue-600' : 'text-gray-600 hover:bg-gray-50'}`}
                >
                    <FileText size={20} />
                    My Profile
                </button>
                <button 
                  onClick={() => setActiveTab('employment')}
                  className={`w-full flex items-center gap-4 px-4 py-3 rounded-xl transition-all duration-200 text-sm font-bold ${activeTab === 'employment' ? 'bg-amber-50 text-amber-600' : 'text-gray-600 hover:bg-gray-50'}`}
                >
                    <Briefcase size={20} />
                    Job Status
                </button>
            </div>
          </div>

          {/* Right Column: Content (9 cols) */}
          <div className="lg:col-span-9 space-y-8">

            {activeTab === 'home' && (
                <>
                {/* Welcome Banner */}
                <div className="bg-gradient-to-r from-luGreen-dark to-luGreen rounded-3xl p-8 text-white shadow-xl relative overflow-hidden">
                    <div className="relative z-10">
                        <h2 className="text-3xl font-display font-bold mb-2">Welcome back, {user.first_name}!</h2>
                        <p className="opacity-90 max-w-xl">Your alumni tracking dashboard is ready. Please keep your profile and employment status up to date.</p>
                    </div>
                    <div className="absolute right-0 bottom-0 opacity-10 transform translate-x-1/4 translate-y-1/4">
                        <User size={200} />
                    </div>
                </div>

                {/* --- ANALYTICS CARDS (New) --- */}
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6 animate-fade-in">

                  {/* Card 1: Information Completion */}
                  <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100 hover:shadow-lg transition-all duration-300 relative overflow-hidden group">
                     <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
                         <PieChart size={80} className="text-luGreen" />
                     </div>
                     <div className="flex flex-col h-full justify-between relative z-10">
                         <div>
                             <div className="flex items-center gap-2 mb-2">
                                <div className="p-2 bg-green-50 rounded-lg text-luGreen">
                                    <TrendingUp size={18} />
                                </div>
                                <span className="text-xs font-bold text-gray-400 uppercase tracking-widest">Profile Status</span>
                             </div>
                             <div className="flex items-end gap-2 mb-2">
                                <h3 className="text-4xl font-bold text-gray-800">{loadingMetrics ? '...' : `${metrics.completionPercentage}%`}</h3>
                                <span className="text-sm font-bold text-gray-400 mb-1.5">Complete</span>
                             </div>
                             {/* Progress Bar */}
                             <div className="w-full h-2 bg-gray-100 rounded-full overflow-hidden mb-2">
                                 <div 
                                    className={`h-full rounded-full transition-all duration-1000 ${metrics.completionPercentage === 100 ? 'bg-luGreen' : 'bg-amber-400'}`} 
                                    style={{ width: `${metrics.completionPercentage}%` }}
                                 ></div>
                             </div>
                             {metrics.completionPercentage < 100 && !loadingMetrics && (
                                <p className="text-[10px] text-red-500 font-bold mt-1 flex items-center gap-1">
                                    <AlertCircle size={10} /> Missing: {metrics.missingSections[0]}
                                </p>
                             )}
                         </div>
                         <button onClick={() => setActiveTab('profile')} className="mt-4 text-xs font-bold text-luGreen hover:text-luGreen-dark flex items-center gap-1">
                             Update Info <ArrowRight size={14} />
                         </button>
                     </div>
                  </div>

                  {/* Card 2: Employment Status */}
                  <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100 hover:shadow-lg transition-all duration-300 relative overflow-hidden group">
                     <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
                         <Briefcase size={80} className="text-blue-500" />
                     </div>
                     <div className="flex flex-col h-full justify-between relative z-10">
                         <div>
                             <div className="flex items-center gap-2 mb-4">
                                <div className="p-2 bg-blue-50 rounded-lg text-blue-600">
                                    <Briefcase size={18} />
                                </div>
                                <span className="text-xs font-bold text-gray-400 uppercase tracking-widest">Employment</span>
                             </div>
                             <h3 className={`text-2xl font-bold mb-1 ${
                                 metrics.employmentStatus === 'Unemployed' ? 'text-red-500' : 
                                 metrics.employmentStatus === 'Unknown' || metrics.employmentStatus === 'Update Status' ? 'text-gray-400' : 'text-gray-800'
                             }`}>
                                 {loadingMetrics ? 'Loading...' : metrics.employmentStatus}
                             </h3>
                             <p className="text-xs font-bold text-gray-400 truncate max-w-[150px]">
                                {metrics.latestCompany || (metrics.employmentStatus === 'Unemployed' ? 'Looking for opportunities' : 'No record found')}
                             </p>
                         </div>
                         <button onClick={() => setActiveTab('employment')} className="mt-4 text-xs font-bold text-blue-600 hover:text-blue-700 flex items-center gap-1">
                             Manage Status <ArrowRight size={14} />
                         </button>
                     </div>
                  </div>

                  {/* Card 3: Job Alignment */}
                  <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100 hover:shadow-lg transition-all duration-300 relative overflow-hidden group">
                     <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
                         <Target size={80} className="text-amber-500" />
                     </div>
                     <div className="flex flex-col h-full justify-between relative z-10">
                         <div>
                             <div className="flex items-center gap-2 mb-4">
                                <div className="p-2 bg-amber-50 rounded-lg text-amber-600">
                                    <Target size={18} />
                                </div>
                                <span className="text-xs font-bold text-gray-400 uppercase tracking-widest">Alignment</span>
                             </div>

                             {loadingMetrics ? (
                                 <h3 className="text-xl font-bold text-gray-400">Loading...</h3>
                             ) : (
                                <>
                                    {metrics.employmentStatus === 'Employed' || metrics.employmentStatus === 'Self-employed' ? (
                                        <div className={`inline-flex items-center px-3 py-1 rounded-full text-xs font-bold border mb-1 ${
                                            metrics.jobAlignment === 'Related' 
                                            ? 'bg-green-100 text-green-700 border-green-200' 
                                            : 'bg-amber-100 text-amber-700 border-amber-200'
                                        }`}>
                                            {metrics.jobAlignment === 'Related' ? <CheckCircle size={12} className="mr-1"/> : <AlertCircle size={12} className="mr-1"/>}
