import React, { useState, useEffect } from 'react';
import { User, FileText, Upload, Save, Loader2, CheckCircle, School, Briefcase, Heart, Star, AlertCircle, ChevronDown, ChevronUp, Plus, Trash2, X, MapPin, Mail, Phone, Edit3, AlertTriangle, GraduationCap, Award, BookOpen, Sparkles } from 'lucide-react';
import { Student, FullProfileData, EmploymentHistory, CommunityEngagement } from '../types';
import FileUpload from './FileUpload';
import { parseResume, uploadResumeToDB, saveProfileData, deleteResumeFromDB, fetchLatestProfile, updateStudentProfile } from '../services/resumeService';
import { supabase } from '../lib/supabaseClient';

interface MyProfilePageProps {
  user: Student;
}

const MyProfilePage: React.FC<MyProfilePageProps> = ({ user }) => {
  const [loading, setLoading] = useState(false);
  const [fetching, setFetching] = useState(true);

  // Resume State
  const [parsing, setParsing] = useState(false);
  const [resumeUploaded, setResumeUploaded] = useState(false); // Initial state false, will fetch
  const [verificationWarning, setVerificationWarning] = useState<string | null>(null);
  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const [deletingResume, setDeletingResume] = useState(false);

  // UI State
  const [savedSuccess, setSavedSuccess] = useState(false);
  const [hasExistingRecord, setHasExistingRecord] = useState(false);
  const [activeSection, setActiveSection] = useState<string | null>(null); // Default closed
  const [isEditingHeader, setIsEditingHeader] = useState(false);
  const [savingHeader, setSavingHeader] = useState(false);

  // Editable Personal Information State
  const [firstName, setFirstName] = useState(user.first_name);
  const [lastName, setLastName] = useState(user.last_name);
  const [email, setEmail] = useState(user.email);
  const [contactNo, setContactNo] = useState(user.contact_no);
  const [address, setAddress] = useState(user.address || '');
  const [program, setProgram] = useState(user.program);
  const [yearLevel, setYearLevel] = useState(user.year_level || '');

  // Profile Data State (Employment, Education, etc.)
  const [profileData, setProfileData] = useState<FullProfileData>({
    education: {},
    employment: [],
    community: [],
    attributes: {
        // Attributes
        professionally_competent: 0,
        critical_thinker: 0,
        communicator: 0,
        lifelong_learner: 0,
        socially_responsible: 0,
        ethical_citizen: 0,
        innovative_worker: 0,
        people_oriented: 0,
        // Skills
        critical_thinking_skill: 0,
        creativity: 0,
        collaboration: 0,
        communication_skill: 0,
        information_literacy: 0,
        media_literacy: 0,
        technology_literacy: 0,
        flexibility: 0,
        leadership: 0,
        initiative: 0,
        productivity: 0,
        social_skills: 0
    }
  });

  // Load latest profile data & Resume Status on mount
  useEffect(() => {
    const loadData = async () => {
        if (!user.id) return;
        try {
            const userType = user.enrollment_status === 'Graduating' ? 'graduating' : 'alumni';
            const table = userType === 'graduating' ? 'students' : 'alumni';

            // 1. Fetch Profile Info
            const data = await fetchLatestProfile(user.id, userType);
            if (data) {
                setProfileData(data);
                setHasExistingRecord(true);
            }

            // 2. Fetch Resume Existence (Persistent Check)
            const { data: resumeCheck } = await supabase
                .from(table)
                .select('id')
                .eq('id', user.id)
                .not('resume', 'is', null)
                .single();

            setResumeUploaded(!!resumeCheck);

        } catch (error) {
            console.error("Failed to load profile", error);
        } finally {
            setFetching(false);
        }
    };
    loadData();
  }, [user.id]);

  const handleResumeUpload = async (file: File) => {
    setParsing(true);
    setVerificationWarning(null);

    try {
        const userType = user.enrollment_status === 'Graduating' ? 'graduating' : 'alumni';

        // 1. Upload Raw File
        await uploadResumeToDB(file, user.id!, userType);
        setResumeUploaded(true);

        // 2. Parse Data
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = async () => {
            const base64Data = (reader.result as string).split(',')[1];
            try {
                const extracted = await parseResume(base64Data, file.type);

                // Verification Logic
                if (extracted.personal) {
                    const extractedLast = extracted.personal.last_name?.toLowerCase() || '';
                    const userLast = lastName.toLowerCase();
                    if (extractedLast && !extractedLast.includes(userLast)) {
                        setVerificationWarning(`Warning: The name on the resume (${extracted.personal.first_name} ${extracted.personal.last_name}) does not match your account name.`);
                    }
                    // Auto-fill address/contact if found and empty
                    if (extracted.personal.address && !address) setAddress(extracted.personal.address);
                    if (extracted.personal.contact_no && !contactNo) setContactNo(extracted.personal.contact_no);
                    if (extracted.personal.email && !email) setEmail(extracted.personal.email);
                }

                setProfileData(prev => ({
                    ...prev,
                    education: { ...prev.education, ...extracted.education },
                    employment: [...(prev.employment || []), ...(extracted.employment || [])],
                    community: [...(prev.community || []), ...(extracted.community || [])],
                }));
            } catch (err) {
                console.error(err);
                alert("Could not parse resume details automatically. Please fill details manually.");
            } finally {
                setParsing(false);
            }
        };
    } catch (error) {
        console.error("Upload error:", error);
        alert("Failed to upload resume.");
        setParsing(false);
    }
  };

  const confirmDeleteResume = async () => {
      setDeletingResume(true);
      try {
          const userType = user.enrollment_status === 'Graduating' ? 'graduating' : 'alumni';
          await deleteResumeFromDB(user.id!, userType);
          setResumeUploaded(false);
          setShowDeleteModal(false);
          setVerificationWarning(null);
      } catch (e) {
          console.error(e);
          alert("Failed to delete resume.");
      } finally {
          setDeletingResume(false);
      }
  };

  const handleInputChange = (section: keyof FullProfileData, field: string, value: any) => {
    setProfileData(prev => ({
        ...prev,
        [section]: {
            ...prev[section],
            [field]: value
        }
    }));
  };

  // --- Employment List Handlers ---
  const addEmployment = () => {
      setProfileData(prev => ({
          ...prev,
          employment: [{ employment_status: 'Employed', is_current_job: false }, ...prev.employment]
      }));
  };

  const removeEmployment = (index: number) => {
      const newEmp = [...profileData.employment];
      newEmp.splice(index, 1);
      setProfileData(prev => ({ ...prev, employment: newEmp }));
  };

  const updateEmployment = (index: number, field: keyof EmploymentHistory, value: any) => {
      const newEmp = [...profileData.employment];
      newEmp[index] = { ...newEmp[index], [field]: value };
      setProfileData(prev => ({ ...prev, employment: newEmp }));
  };

  // --- Community List Handlers ---
  const addCommunity = () => {
      setProfileData(prev => ({
          ...prev,
          community: [{}, ...prev.community]
      }));
  };

  const removeCommunity = (index: number) => {
      const newComm = [...profileData.community];
      newComm.splice(index, 1);
      setProfileData(prev => ({ ...prev, community: newComm }));
  };

  const updateCommunity = (index: number, field: keyof CommunityEngagement, value: any) => {
      const newComm = [...profileData.community];
      newComm[index] = { ...newComm[index], [field]: value };
      setProfileData(prev => ({ ...prev, community: newComm }));
  };

  // --- SAVE ACTIONS ---

  const handleSaveHeader = async () => {
    setSavingHeader(true);
    try {
        const userType = user.enrollment_status === 'Graduating' ? 'graduating' : 'alumni';
        await updateStudentProfile(user.id!, userType, {
            first_name: firstName,
            last_name: lastName,
            email: email,
            contact_no: contactNo,
            address: address,
            program: program,
            year_level: yearLevel
        });
        setIsEditingHeader(false);
        setSavedSuccess(true);
        setTimeout(() => setSavedSuccess(false), 3000);
    } catch (error) {
        console.error("Header save error:", error);
        alert("Failed to update personal information.");
    } finally {
        setSavingHeader(false);
    }
  };

  const handleSaveAllData = async () => {
    setLoading(true);
    try {
        const userType = user.enrollment_status === 'Graduating' ? 'graduating' : 'alumni';

        // Ensure header data is also synced just in case
        await updateStudentProfile(user.id!, userType, {
            first_name: firstName,
            last_name: lastName,
            email: email,
            contact_no: contactNo,
            address: address,
            program: program,
            year_level: yearLevel
        });

        // Save Accordion Data
        await saveProfileData(user.id!, userType, profileData);

        setHasExistingRecord(true);
        setSavedSuccess(true);
        setTimeout(() => setSavedSuccess(false), 3000);
    } catch (error) {
        console.error("Save error:", error);
        alert("Failed to save profile.");
    } finally {
        setLoading(false);
    }
  };

  const toggleSection = (section: string) => {
      setActiveSection(activeSection === section ? null : section);
  };

  // Render Helpers
  const renderInput = (section: keyof FullProfileData, field: string, label: string, type: string = "text", placeholder: string = "") => (
      <div className="space-y-1.5 group">
          <label className="text-[11px] font-bold text-gray-400 uppercase tracking-wide group-focus-within:text-luGreen transition-colors">{label}</label>
          <input 
            type={type} 
            value={(profileData[section] as any)[field] || ''} 
            onChange={(e) => handleInputChange(section, field, e.target.value)}
            className="w-full px-4 py-3 rounded-xl bg-gray-50 border border-gray-100 focus:bg-white focus:border-luGreen focus:outline-none focus:ring-4 focus:ring-green-500/10 text-sm font-medium text-gray-700 transition-all shadow-sm"
            placeholder={placeholder}
          />
      </div>
  );

  const renderRating = (field: string, label: string) => (
      <div className="flex items-center justify-between p-4 bg-gray-50/50 rounded-xl hover:bg-white hover:shadow-md border border-transparent hover:border-gray-100 transition-all duration-300">
          <span className="text-sm font-bold text-gray-700">{label}</span>
          <div className="flex gap-1">
              {[1, 2, 3, 4, 5].map((star) => (
                  <button 
                    key={star} 
                    type="button"
                    onClick={() => handleInputChange('attributes', field, star)}
                    className={`p-1.5 rounded-full transition-all hover:scale-110 active:scale-95 ${
                        (profileData.attributes as any)[field] >= star 
                        ? 'text-yellow-400 drop-shadow-sm' 
                        : 'text-gray-200 hover:text-yellow-200'
                    }`}
                  >
                      <Star size={20} fill={(profileData.attributes as any)[field] >= star ? "currentColor" : "none"} />
                  </button>
              ))}
          </div>
      </div>
  );

  if (fetching) {
      return (
          <div className="bg-white rounded-3xl shadow-sm border border-gray-100 min-h-[600px] flex items-center justify-center animate-pulse">
              <div className="flex flex-col items-center">
                  <div className="w-16 h-16 bg-gray-100 rounded-full mb-4 relative overflow-hidden">
                      <div className="absolute inset-0 bg-gradient-to-tr from-gray-100 to-gray-200 animate-spin-slow"></div>
                  </div>
                  <Loader2 className="w-8 h-8 animate-spin text-luGreen mb-2" />
                  <p className="text-gray-400 text-xs font-bold uppercase tracking-widest">Loading profile data...</p>
              </div>
          </div>
      );
  }

  return (
    <>
    <div className="space-y-6 pb-8">

        {/* === HEADER CARD === */}
        <div className="bg-white rounded-[2rem] shadow-lg shadow-gray-200/50 border border-gray-100 overflow-hidden relative group">

            {/* Artistic Header Background */}
            <div className="h-64 relative overflow-hidden">
                <div className="absolute inset-0 bg-gradient-to-br from-gray-900 via-luGreen-dark to-emerald-900"></div>
                <div className="absolute inset-0 opacity-20" style={{ 
                    backgroundImage: `radial-gradient(circle at 2px 2px, rgba(255,255,255,0.2) 1px, transparent 0)`,
                    backgroundSize: '24px 24px' 
                }}></div>
                <div className="absolute -right-20 -top-40 w-[500px] h-[500px] bg-luGreen/30 rounded-full blur-3xl mix-blend-overlay"></div>
                <div className="absolute -left-20 bottom-0 w-[300px] h-[300px] bg-luGold/20 rounded-full blur-3xl mix-blend-overlay"></div>

                {/* Status Badge */}
                <div className="absolute top-6 right-8 z-20">
                     {savedSuccess && (
                        <div className="flex items-center gap-2 text-luGreen-dark bg-white/95 backdrop-blur-md px-4 py-2 rounded-full animate-fade-in shadow-xl text-sm font-bold border border-green-100">
                            <CheckCircle size={16} className="text-luGreen" /> Saved Successfully!
                        </div>
                    )}
                </div>
            </div>

            {/* Profile Content Overlapping Header */}
            <div className="px-8 pb-8 -mt-20 relative z-10">
                <div className="flex flex-col lg:flex-row gap-8">

                     {/* Avatar Column */}
                     <div className="flex-shrink-0 mx-auto lg:mx-0 text-center lg:text-left">
                        <div className="relative inline-block">
                             <div className="w-40 h-40 rounded-[2rem] bg-white p-1.5 shadow-2xl shadow-black/10">
                                 <div className="w-full h-full rounded-[1.7rem] bg-gray-50 flex items-center justify-center text-gray-300 overflow-hidden border border-gray-100 relative group cursor-pointer hover:bg-gray-100 transition-colors">
                                    <User size={64} className="opacity-40" />
                                    <div className="absolute inset-0 bg-black/40 backdrop-blur-[2px] flex flex-col items-center justify-center opacity-0 group-hover:opacity-100 transition-all duration-300">
                                        <Upload size={24} className="text-white mb-1" />
                                        <span className="text-white text-[10px] font-bold uppercase tracking-wider">Change Photo</span>
                                    </div>
                                </div>
                            </div>
                            <div className="absolute -bottom-3 -right-3 bg-white p-1 rounded-full shadow-lg">
                                <div className="bg-luGreen text-white p-2 rounded-full">
                                    <Edit3 size={14} />
                                </div>
                            </div>
                        </div>
