                </button>
                {activeSection === 'attributes' && (
                    <div className="p-6 md:p-8 bg-gray-50/50 animate-slide-up border-t border-gray-100">
                        <div className="bg-purple-50 rounded-xl p-4 mb-6 border border-purple-100 flex gap-4 items-center">
                            <div className="p-2 bg-white rounded-lg shadow-sm text-purple-600">
                                <Star size={20} />
                            </div>
                            <p className="text-sm text-purple-900 font-medium">
                                Rate yourself on the following attributes from <strong>1 (Lowest)</strong> to <strong>5 (Highest)</strong>.
                            </p>
                        </div>

                        <div className="space-y-8">
                            {/* Group 1: Institutional Attributes */}
                            <div>
                                <h5 className="font-bold text-gray-900 text-sm mb-4 uppercase tracking-wider flex items-center gap-2">
                                    <span className="w-1.5 h-6 bg-luGreen rounded-full"></span>
                                    Institutional Graduate Attributes
                                </h5>
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                    {renderRating('professionally_competent', 'Professionally Competent')}
                                    {renderRating('critical_thinker', 'Critical Thinker')}
                                    {renderRating('communicator', 'Communicator')}
                                    {renderRating('lifelong_learner', 'Lifelong Learner')}
                                    {renderRating('socially_responsible', 'Socially Responsible')}
                                    {renderRating('ethical_citizen', 'Ethical Citizen')}
                                    {renderRating('innovative_worker', 'Innovative Worker')}
                                    {renderRating('people_oriented', 'People Oriented')}
                                </div>
                            </div>

                            {/* Group 2: Skills */}
                            <div>
                                <h5 className="font-bold text-gray-900 text-sm mb-4 uppercase tracking-wider flex items-center gap-2 pt-4 border-t border-gray-200/50">
                                    <span className="w-1.5 h-6 bg-luGold rounded-full"></span>
                                    21st Century Skills & Literacies
                                </h5>
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                    {renderRating('critical_thinking_skill', 'Critical Thinking')}
                                    {renderRating('creativity', 'Creativity')}
                                    {renderRating('collaboration', 'Collaboration')}
                                    {renderRating('communication_skill', 'Communication Skills')}
                                    {renderRating('information_literacy', 'Information Literacy')}
                                    {renderRating('media_literacy', 'Media Literacy')}
                                    {renderRating('technology_literacy', 'Technology Literacy')}
                                    {renderRating('flexibility', 'Flexibility')}
                                    {renderRating('leadership', 'Leadership')}
                                    {renderRating('initiative', 'Initiative')}
                                    {renderRating('productivity', 'Productivity')}
                                    {renderRating('social_skills', 'Social Skills')}
                                </div>
                            </div>
                        </div>

                    </div>
                )}
            </div>

            {/* Save Button (Moved from bottom fixed bar) */}
            <div className="flex justify-end pt-6 pb-12">
                 <button 
                    onClick={handleSaveAllData}
                    disabled={loading}
                    className="px-8 py-3.5 bg-gradient-to-r from-luGreen to-emerald-600 text-white font-bold rounded-2xl shadow-lg shadow-green-900/20 hover:shadow-xl hover:shadow-green-900/30 hover:-translate-y-1 transition-all flex items-center justify-center gap-3 group"
                >
                    {loading ? (
                        <>
                            <Loader2 className="animate-spin w-5 h-5" />
                            <span>Processing...</span>
                        </>
                    ) : (
                        <>
                            <Save size={20} className="group-hover:scale-110 transition-transform" />
                            <span>{hasExistingRecord ? "Update Profile" : "Save Full Profile"}</span>
                        </>
                    )}
                </button>
            </div>

        </div>
    </div>

    {/* Custom Delete Confirmation Modal */}
    {showDeleteModal && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-gray-900/60 backdrop-blur-sm animate-fade-in" onClick={() => setShowDeleteModal(false)}></div>
            <div className="bg-white rounded-[2rem] shadow-2xl w-full max-w-md relative z-10 overflow-hidden animate-blob border border-gray-100">
                <div className="p-10 text-center">
                    <div className="w-20 h-20 bg-red-50 rounded-full flex items-center justify-center mx-auto mb-6 shadow-sm">
                        <AlertTriangle className="w-10 h-10 text-red-500" />
                    </div>
                    <h3 className="text-2xl font-bold text-gray-900 mb-3 font-display">Delete Resume File?</h3>
                    <p className="text-gray-500 text-base mb-8 leading-relaxed">
                        Are you sure you want to remove your resume file from the system? This action cannot be undone and will remove extracted data source.
                    </p>

                    <div className="flex gap-4">
                         <button 
                            onClick={() => setShowDeleteModal(false)}
                            className="flex-1 py-3.5 bg-gray-50 hover:bg-gray-100 text-gray-700 font-bold rounded-xl transition-colors"
                        >
                            Cancel
                        </button>
                        <button 
                            onClick={confirmDeleteResume}
                            disabled={deletingResume}
                            className="flex-1 py-3.5 bg-red-500 hover:bg-red-600 text-white font-bold rounded-xl shadow-lg shadow-red-200 transition-all flex items-center justify-center gap-2"
                        >
                            {deletingResume ? <Loader2 size={18} className="animate-spin" /> : <Trash2 size={18} />}
                            Yes, Delete It
                        </button>
                    </div>
                </div>
            </div>
        </div>
    )}
    </>
  );
};

export default MyProfilePage;
